 							: undefined,
 				},
 			} as unknown as AgentChatSessionStore,
 			registry: {
 				onDidChange: new EventEmitter<void>().event,
 				listActive: () => [registrySession],
 				listRecent: () => [],
 			} as unknown as AgentChatRegistry,
 			agentChatStoreChangeEvent: new EventEmitter<unknown>().event,
 			cloudSessionStorage: {
 				getAll: () => Promise.resolve([]),
 			} as unknown as AgentSessionStorage,
 		});

 		const snapshot = await model.snapshot();
 		const [session] = snapshot.sessions;

 		expect(snapshot.sessions).toHaveLength(1);
 		expect(session).toMatchObject({
 			source: "agent-chat",
 			sourceSessionId: "agent-live",
 			state: "waiting-for-input",
 			bucket: "waiting",
 			isBlocked: true,
 			worktreeStatus: "in-use",
 			executionTargetLabel: "Worktree",
 			updatedAt: 20,
 			lastVisibleActivityAt: 30,
 			title: "Investigate the orchestration refresh race in the sidebar view.",
 		});
 	});

 	it("reports degraded state when cloud storage is unavailable", async () => {
 		const model = new OrchestrationReadModel({
 			store: {
 				listActive: () => Promise.resolve([]),
 				listRecent: () => Promise.resolve([]),
 				workspaceState: {
 					get: () => {
 						return;
 					},
 				},
 			} as unknown as AgentChatSessionStore,
 			registry: {
 				onDidChange: new EventEmitter<void>().event,
 				listActive: () => [],
 				listRecent: () => [],
 			} as unknown as AgentChatRegistry,
 			agentChatStoreChangeEvent: new EventEmitter<unknown>().event,
 		});

 		const snapshot = await model.snapshot();

 		expect(snapshot.sessions).toEqual([]);
 		expect(snapshot.degradedReasons).toContain(
 			"Cloud agent session storage is unavailable."
 		);
 		expect(snapshot.degradedReasons).toContain(
 			"Cloud agent provider wiring is unavailable. Open Agent Chat or refresh Cloud Agents after the provider surface is restored."
 		);
 		expect(snapshot.cloudProviderRegistryAvailable).toBe(false);
 		expect(snapshot.cloudProviderCount).toBe(0);
 	});

 	it("reports degraded state when cloud status reads fail or no provider is active", async () => {
 		const model = new OrchestrationReadModel({
 			store: {
 				listActive: () => Promise.resolve([]),
 				listRecent: () => Promise.resolve([]),
 				workspaceState: {
 					get: () => {
 						return;
 					},
 				},
 			} as unknown as AgentChatSessionStore,
 			registry: {
 				onDidChange: new EventEmitter<void>().event,
 				listActive: () => [],
 				listRecent: () => [],
 			} as unknown as AgentChatRegistry,
 			agentChatStoreChangeEvent: new EventEmitter<unknown>().event,
 			cloudSessionStorage: {
 				getAll: () => Promise.reject(new Error("boom")),
 			} as unknown as AgentSessionStorage,
 			cloudProviderRegistry: {
 				getAll: () => [{ metadata: { id: "devin", displayName: "Devin" } }],
 				getActive: () => null,
 				get: () => null,
 			} as unknown as ProviderRegistry,
 		});

 		const snapshot = await model.snapshot();

 		expect(snapshot.sessions).toEqual([]);
 		expect(snapshot.cloudProviderRegistryAvailable).toBe(true);
 		expect(snapshot.cloudProviderCount).toBe(1);
 		expect(snapshot.degradedReasons).toContain(
 			"Cloud agent status could not be read."
 		);
 	});
+
+	it("emits change notifications for store, registry, and cloud updates until disposed", () => {
+		const storeEmitter = new EventEmitter<unknown>();
+		const registryEmitter = new EventEmitter<void>();
+		const cloudSessionsEmitter = new EventEmitter<void>();
+		const cloudProviderEmitter = new EventEmitter<void>();
+		const listener = vi.fn();
+
+		const model = new OrchestrationReadModel({
+			store: {
+				listActive: () => Promise.resolve([]),
+				listRecent: () => Promise.resolve([]),
+				workspaceState: {
+					get: () => {
+						return;
+					},
+				},
+			} as unknown as AgentChatSessionStore,
+			registry: {
+				onDidChange: registryEmitter.event,
+				listActive: () => [],
+				listRecent: () => [],
+			} as unknown as AgentChatRegistry,
+			agentChatStoreChangeEvent: storeEmitter.event,
+			onCloudSessionsChanged: (callback) =>
+				cloudSessionsEmitter.event(callback),
+			onCloudProviderChanged: (callback) =>
+				cloudProviderEmitter.event(callback),
+		});
+
+		model.onDidChange(listener);
+
+		storeEmitter.fire(undefined);
+		registryEmitter.fire();
+		cloudSessionsEmitter.fire();
+		cloudProviderEmitter.fire();
+
+		expect(listener).toHaveBeenCalledTimes(4);
+
+		model.dispose();
+		storeEmitter.fire(undefined);
+		registryEmitter.fire();
+		cloudSessionsEmitter.fire();
+		cloudProviderEmitter.fire();
+
+		expect(listener).toHaveBeenCalledTimes(4);
+	});
+
+	it("falls back to provider id and spec path when cloud session details are minimal", async () => {
+		const model = new OrchestrationReadModel({
+			store: {
+				listActive: () => Promise.resolve([]),
+				listRecent: () => Promise.resolve([]),
+				workspaceState: {
+					get: () => {
+						return;
+					},
+				},
+			} as unknown as AgentChatSessionStore,
+			registry: {
+				onDidChange: new EventEmitter<void>().event,
+				listActive: () => [],
+				listRecent: () => [],
+			} as unknown as AgentChatRegistry,
+			agentChatStoreChangeEvent: new EventEmitter<unknown>().event,
+			cloudSessionStorage: {
+				getAll: () =>
+					Promise.resolve([
+						makeCloudSession({
+							localId: "cloud-minimal",
+							providerId: "custom-provider",
+							specPath: "specs/018-agent-chat-panel/tasks.md",
+							tasks: [],
+							status: SessionStatus.COMPLETED,
+							completedAt: 33,
+							isReadOnly: true,
+						}),
+					]),
+			} as unknown as AgentSessionStorage,
+			cloudProviderRegistry: {
+				getAll: () => [{ metadata: { id: "devin", displayName: "Devin" } }],
+				getActive: () => {
+					return;
+				},
+				get: () => {
+					return;
+				},
+			} as unknown as ProviderRegistry,
+		});
+
+		const snapshot = await model.snapshot();
+		const [session] = snapshot.sessions;
+
+		expect(session).toMatchObject({
+			source: "cloud-agent",
+			sourceSessionId: "cloud-minimal",
+			title: "specs/018-agent-chat-panel/tasks.md",
+			agentName: "custom-provider",
+			bucket: "completed",
+			endedAt: 33,
+			worktreeStatus: "read-only",
+			executionTargetLabel: "Cloud",
+		});
+	});
 });

Index: tests/unit/providers/orchestration-view-provider.test.ts
===================================================================
--- tests/unit/providers/orchestration-view-provider.test.ts	
+++ tests/unit/providers/orchestration-view-provider.test.ts	
@@ -0,0 +1,259 @@
+import { beforeEach, describe, expect, it, vi } from "vitest";
+import { commands, env, EventEmitter, Uri } from "vscode";
+import { OrchestrationViewProvider } from "../../../src/providers/orchestration-view-provider";
+import type {
+	OrchestrationReadModel,
+	OrchestrationSnapshot,
+} from "../../../src/features/orchestration/orchestration-read-model";
+
+vi.mock("../../../src/utils/get-webview-content", () => ({
+	getWebviewContent: vi.fn(() => "<html></html>"),
+}));
+
+function makeSnapshot(
+	overrides: Partial<OrchestrationSnapshot> = {}
+): OrchestrationSnapshot {
+	return {
+		sessions: [],
+		cloudProviderRegistryAvailable: true,
+		cloudProviderCount: 1,
+		activeProvider: {
+			id: "devin",
+			displayName: "Devin",
+		},
+		generatedAt: 1_710_000_000_000,
+		degradedReasons: [],
+		...overrides,
+	};
+}
+
+interface FakeWebview {
+	html: string;
+	options: unknown;
+	postMessage: ReturnType<typeof vi.fn>;
+	onDidReceiveMessage: ReturnType<typeof vi.fn>;
+	_inject(message: unknown): Promise<void>;
+}
+
+interface FakeWebviewView {
+	webview: FakeWebview;
+	show: ReturnType<typeof vi.fn>;
+}
+
+function createFakeView(): FakeWebviewView {
+	const listeners: Array<(message: unknown) => void | Promise<void>> = [];
+	const webview: FakeWebview = {
+		html: "",
+		options: {},
+		postMessage: vi.fn(() => Promise.resolve(true)),
+		onDidReceiveMessage: vi.fn((listener: (message: unknown) => void) => {
+			listeners.push(listener);
+			return { dispose: vi.fn() };
+		}),
+		_inject: async (message) => {
+			for (const listener of listeners) {
+				await listener(message);
+			}
+		},
+	};
+
+	return {
+		webview,
+		show: vi.fn(),
+	};
+}
+
+async function flushMicrotasks(): Promise<void> {
+	await Promise.resolve();
+	await Promise.resolve();
+}
+
+describe("OrchestrationViewProvider", () => {
+	beforeEach(() => {
+		vi.clearAllMocks();
+		vi.mocked(commands.executeCommand).mockResolvedValue(undefined as never);
+		vi.mocked(env.openExternal).mockResolvedValue(true);
+	});
+
+	it("pushes the current snapshot on resolve and when the read model changes", async () => {
+		const changeEmitter = new EventEmitter<void>();
+		const snapshot = makeSnapshot({
+			sessions: [
+				{
+					id: "agent-chat:session-1",
+					source: "agent-chat",
+					sourceSessionId: "session-1",
+					title: "Investigate orchestration refresh race",
+					agentName: "OpenCode",
+					state: "running",
+					bucket: "active",
+					createdAt: 1,
+					updatedAt: 2,
+					lastVisibleActivityAt: 3,
+					isBlocked: false,
+					openSessionCommand: { kind: "agent-chat", sessionId: "session-1" },
+				},
+			],
+		});
+		const readModel = {
+			snapshot: vi.fn().mockResolvedValue(snapshot),
+			onDidChange: (listener: () => void) => changeEmitter.event(listener),
+		} as unknown as OrchestrationReadModel;
+		const provider = new OrchestrationViewProvider({
+			context: { extensionUri: Uri.file("/fake/extension") } as never,
+			readModel,
+		});
+		const view = createFakeView();
+
+		provider.resolveWebviewView(view as never, {} as never, {} as never);
+		await flushMicrotasks();
+
+		expect(view.webview.postMessage).toHaveBeenCalledWith({
+			type: "orchestration/snapshot",
+			payload: snapshot,
+		});
+
+		view.webview.postMessage.mockClear();
+		changeEmitter.fire();
+		await flushMicrotasks();
+
+		expect(view.webview.postMessage).toHaveBeenCalledWith({
+			type: "orchestration/snapshot",
+			payload: snapshot,
+		});
+	});
+
+	it("dispatches refresh, open-session, and external navigation commands", async () => {
+		const snapshot = makeSnapshot({
+			sessions: [
+				{
+					id: "agent-chat:session-1",
+					source: "agent-chat",
+					sourceSessionId: "session-1",
+					title: "Resume local chat",
+					agentName: "OpenCode",
+					state: "running",
+					bucket: "active",
+					createdAt: 1,
+					updatedAt: 2,
+					lastVisibleActivityAt: 3,
+					isBlocked: false,
+					openSessionCommand: { kind: "agent-chat", sessionId: "session-1" },
+				},
+				{
+					id: "cloud-agent:session-2",
+					source: "cloud-agent",
+					sourceSessionId: "session-2",
+					title: "Open remote run",
+					agentName: "Devin",
+					state: "failed",
+					bucket: "failed",
+					createdAt: 4,
+					updatedAt: 5,
+					lastVisibleActivityAt: 6,
+					isBlocked: false,
+					externalUrl: "https://example.test/session-2",
+					openSessionCommand: {
+						kind: "cloud-agent",
+						localId: "session-2",
+						externalUrl: "https://example.test/session-2",
+					},
+				},
+			],
+		});
+		const readModel = {
+			snapshot: vi.fn().mockResolvedValue(snapshot),
+			onDidChange: () => ({ dispose: vi.fn() }),
+		} as unknown as OrchestrationReadModel;
+		const provider = new OrchestrationViewProvider({
+			context: { extensionUri: Uri.file("/fake/extension") } as never,
+			readModel,
+		});
+		const view = createFakeView();
+
+		provider.resolveWebviewView(view as never, {} as never, {} as never);
+		await flushMicrotasks();
+		vi.mocked(commands.executeCommand).mockClear();
+
+		await view.webview._inject({ type: "orchestration/refresh" });
+		await flushMicrotasks();
+		expect(commands.executeCommand).toHaveBeenNthCalledWith(
+			1,
+			"gatomia.views.cloudAgents.focus"
+		);
+		expect(commands.executeCommand).toHaveBeenNthCalledWith(
+			2,
+			"gatomia.refreshCloudAgents"
+		);
+
+		vi.mocked(commands.executeCommand).mockClear();
+		await view.webview._inject({
+			type: "orchestration/open-session",
+			payload: { sessionId: "agent-chat:session-1" },
+		});
+		await flushMicrotasks();
+		expect(commands.executeCommand).toHaveBeenCalledWith(
+			"gatomia.agentChat.openForSession",
+			"session-1"
+		);
+
+		await view.webview._inject({
+			type: "orchestration/open-session",
+			payload: { sessionId: "cloud-agent:session-2" },
+		});
+		await flushMicrotasks();
+		expect(vi.mocked(env.openExternal).mock.calls.at(-1)?.[0]?.toString()).toBe(
+			"https://example.test/session-2"
+		);
+
+		await view.webview._inject({
+			type: "orchestration/open-existing-surface",
+			payload: { source: "cloud-agent" },
+		});
+		await flushMicrotasks();
+		expect(commands.executeCommand).toHaveBeenCalledWith(
+			"gatomia.refreshCloudAgents"
+		);
+
+		await view.webview._inject({
+			type: "orchestration/open-external",
+			payload: { url: "https://example.test/direct" },
+		});
+		await flushMicrotasks();
+		expect(vi.mocked(env.openExternal).mock.calls.at(-1)?.[0]?.toString()).toBe(
+			"https://example.test/direct"
+		);
+	});
+
+	it("posts a degraded fallback snapshot when snapshot reads fail", async () => {
+		const readModel = {
+			snapshot: vi.fn().mockRejectedValue(new Error("boom")),
+			onDidChange: () => ({ dispose: vi.fn() }),
+		} as unknown as OrchestrationReadModel;
+		const outputChannel = { appendLine: vi.fn() };
+		const provider = new OrchestrationViewProvider({
+			context: { extensionUri: Uri.file("/fake/extension") } as never,
